Consider the following ANSI C program:

#include <stdio.h>
#include <stdlib.h>
struct Node {
    int value;
    struct Node *next;
};
int main() {
    struct Node *boxE, *head, *boxN;
    int index = 0;
    boxE = head = (struct Node *) malloc(sizeof(struct Node));
    head->value = index;
    for (index = 1; index <= 3; index++) {
        boxN = (struct Node *) malloc(sizeof(struct Node));
        boxN->value = index;
        boxE->next = boxN;
        boxE = boxN;
    }
    boxE->next = head;
    index = 0;
    while (head->next != NULL) {
        printf("%d ", head->value);
        head = head->next;
        index++;
        if (index > 5) break;
    }
    return 0;
}

Which one of the following statements is correct about the program?

A. Upon execution, the program creates a linked-list of five nodes
B. Upon execution, the program goes into an infinite loop
C. It has a missing return which will be reported as an error by the compiler
D. It dereferences an uninitialized pointer that may result in a run-time error

Consider the following C program:

#include <stdio.h>
typedef struct {
    char *a;
    char *b;
} t;

void f1(t s) {
    s.a = "U";
    s.b = "V";
}

void f2(t *p) {
    p->a = "V";
    p->b = "W";
}

void f3(t *p) {
    t s = {"V", "W"};
    *p = s;
    p->a = "X";
}

main() {
    static t s = {"A", "B"};
    printf("%s %s\n", s.a, s.b);
    f1(s);
    printf("%s %s\n", s.a, s.b);
    f2(&s);
    printf("%s %s\n", s.a, s.b);
    f3(&s);
    printf("%s %s\n", s.a, s.b);
}

What is the output generated by the program?

A. A B
   A B
   V W
   X W
B. A B
   U V
   V W
   X W
C. A B
   A B
   V W
   V W
D. A B
   U V
   A B
   X W
